    // first try to load from user defaults
    _uuid = WBSettingManager.sharedManager.UUID;
    if (_uuid != nil) {
        NSLog(@"[AUTH] uuid from userdefaults:%@", _uuid);
        return TRUE;
    }
    // if user defaults's not available (the app might be deleted and reinstalled), try load from keychain
    if ([self loadUUIDFromKeychain]) {
        NSLog(@"[AUTH] uuid from keychain:%@", _uuid);
        // save it to userdefaults so that next time we could load from userdefaults (fast)
        WBSettingManager.sharedManager.UUID = _uuid;
        NSLog(@"[AUTH] uuid saved to userdefaults.");
        return TRUE;
    }
    return FALSE;
}


